def binary_search(arr, x, low, high):
    """
    Belirtilen aralıkta ikili arama yapar.
    """
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == x:
            return mid
        elif arr[mid] < x:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def exponential_search(arr, x):
    """
    Üstel Arama (Exponential Search) algoritmasını uygular.
    Büyük ve sıralı diziler için uygundur.
    """
    n = len(arr)

    if n == 0:
        return -1

    # Hedef eleman ilk pozisyondaysa hemen döndür
    if arr[0] == x:
        return 0

    # Hedef elemanın bulunabileceği aralığı (bound) belirle
    # bound'u 1'den başlayarak ikiye katla
    bound = 1
    while bound < n and arr[bound] < x:
        bound *= 2

    # Belirlenen aralıkta ikili arama yap
    # İkili arama aralığı: [bound // 2, min(bound, n - 1)]
    return binary_search(arr, x, bound // 2, min(bound, n - 1))
